var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"여기는…… 병원이 들어서기로 한 건설 현장이잖아?","JPN":"ここは……病院が建設される予定の現場じゃないか？","ENG":"This is... the construction site where the new hospital is supposed to be built.","TWN":"這裡……是醫院重建的工地吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이곳에 병원이 세워진다고?","JPN":"ここに病院が建設されるの？","ENG":"They're building a new hospital here?","TWN":"嗯？這裡又要建新的醫院了？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"맞아. 내가 알기로는 공사가 거의 끝나서 내년 초쯤에는 완공된다고 들었어.","JPN":"うん、確か工事は結構進んでいて、来年の頭頃には完成されるって聞いた。","ENG":"Right. From what I know, the construction is nearly complete and scheduled for completion early next year.","TWN":"沒錯。據我了解，已經快完工了，聽說明年初就能完工。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음, 그런 거였구나?","JPN":"へえ、そうだったんだ。","ENG":"Mm, is that so?","TWN":"唔，原來如此……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼, 침식 재난이 일어날 만도 하겠어.","JPN":"それなら侵食災難が起こってもおかしくないね。","ENG":"Then it's quite possible that a Corruption disaster will occur.","TWN":"那麼，這裡會發生侵蝕災難也就不奇怪了。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무슨 소리야? 병원이 들어오는 거랑, 괴물이 나타나는 게 무슨 상관인데?","JPN":"どういう意味だ？　ここに病院が建てられるのと化け物と何の関係がある？","ENG":"What are you talking about? What does a hospital being built have to do with monsters appearing?","TWN":"你這是什麼意思？重新建造的醫院和侵蝕怪物的出現又有什麼關係？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"현실에서 발생하는 침식 현상은 때때로 인간의 집단무의식에 의한 CRF에 영향을 받거든.","JPN":"現実で発生する侵食現象は、時々人間の集団無意識によるCRFに影響されるの。","ENG":"Counterside Effects in the real world are sometimes affected by CRF caused by humans' collective subconsciousness.","TWN":"現實中發生的侵蝕現象有時會受到人類集體無意識的CRF影響。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"CPR? 심폐소생술?","JPN":"CPR？　心肺蘇生法のことか？","ENG":"CFR? Do you mean CPR?","TWN":"CPR？心肺復甦？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"CRF라고 해. <color=#ffd34c>현실을 개변하는 힘</color>이지.","JPN":"CRFよ。<color=#ffd34c>現実を改変する力</color>のこと。","ENG":"I meant CRF. It stands for <color=#ffd34c>Counter Reality Force</color>.","TWN":"是CRF。<color=#ffd34c>改變現實的力量</color>。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이 근처 병원에서 발생했던 화재 사고가 주민들의 무의식에 영향을 준 거야.","JPN":"近くの病院で火災事故が発生したでしょう。それが住民たちの無意識に影響を与えたの。","ENG":"The fire incident that occurred at the hospital nearby affected the subconsciousness of the residents here.","TWN":"醫院發生的火災事故，影響了附近居民的潛意識。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 스스로도 자각하지 못하는 부정적인 감정으로 인해 침식 현상이 유발된 거지.","JPN":"住民たち自らも自覚していないネガティブな感情によって、侵食現象が起きたってことね。","ENG":"And the unconscious negative emotions triggered the Counterside Effect.","TWN":"而我們潛意識中的負面情緒又會誘發侵蝕現象。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"인간의 무의식이 현실에 영향을 준다고?","JPN":"人間の無意識が現実に影響しただと？","ENG":"Human's unconsciousness affects the real world?","TWN":"人類的潛意識會影響現實？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무슨 그런 터무니없는…….","JPN":"そんなバカな……","ENG":"That's nonsense...","TWN":"什麼亂七八糟的……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음, 글쎄?","JPN":"うーん、そうねえ？","ENG":"Mm, is it?","TWN":"嗯，很荒謬吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 믿든, 믿지 않든 그게 이 세계의 진실인 걸?","JPN":"あなたが信じようが信じまいが、それがこの世界の真実なのよ？","ENG":"Whether you believe it or not, it's the truth of this world.","TWN":"不管你信不信，這就是這個世界的真相。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"오셨습니까, 야크샤 부전대장님.","JPN":"来てくれましたか、ヤクシャー副戦隊長。","ENG":"We've been waiting for you, Yaksha Deputy Commander.","TWN":"你來了，夜叉副戰隊長。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"곧 이곳의 CSE 레벨이 3단계까지 상승한다는 테라브레인의 예보가 있었습니다.","JPN":"もうすぐここのCSEレベルが3段階まで上がるというテラブレインの予報がありました。","ENG":"There was a forecast from Terrabrain that the CSE Level in this area will soon rise to Level 3.","TWN":"據特拉大腦預測，這裡的CSE等級很快將升至3。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"절차에 따라, 혹시 모를 경우를 대비하여 현실에 주둔하고 계신 전대 분들께 협조를 요청드렸고요.","JPN":"万が一に備えて、現実に駐屯している戦隊の皆さんに協力をお願いしたのです。","ENG":"According to protocol, we requested help from divisions stationed in the Normalside in case anything went wrong.","TWN":"按照程式，我們應請求現實世界駐守的戰隊予以配合。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"괜찮아. 현실세계에서 대 침식 작전에 협력하는 것도 전대의 의무니까.","JPN":"いいのよ、現実世界で対侵食作戦に協力するのも、戦隊の義務だからね。","ENG":"No worries. It's our duty to cooperate with anti-Corruption operations while in the Normalside.","TWN":"沒關係。在現世中，配合抵抗侵蝕作戰也是戰隊的義務。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 현 상황은?","JPN":"それで、現状は？","ENG":"So, what's the current situation?","TWN":"目前情況怎麼樣？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"현재 현장 요원들이 작전 구역에 인지 왜곡 필터를 설치 중입니다.","JPN":"現在、現場エージェントたちが作戦区域に認知歪曲フィルターを設置しています。","ENG":"Our field agents are currently installing awareness distortion filters in the area.","TWN":"現場人員目前正在作戰區域安裝認知失真濾波器。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"다행히 늦은 시간이라 현장에 공사 인원은 남아 있지 않은 것으로 확인되습니다.","JPN":"すでに遅い時間ですので、現場に工事関係者は残っていません。","ENG":"Fortunately, it's late, and we confirmed that there are no construction workers left on the site.","TWN":"幸好是晚上，經確認現場已無建築工人留下。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"CSE레벨이 3단계까지 올라가면, 3종 침식체가 나타날 수도 있는데.","JPN":"CSEレベルが3段階まで上がると、第3種侵食体が現れる可能性もあるんだけど。","ENG":"If the CSE Level goes up to 3, that means a Category 3 C.O. can appear.","TWN":"當CSE等級升至3時，可能會出現3類侵蝕體。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"조금 요란해져도 괜찮을까?","JPN":"ちょっと派手な戦いになっても構わないかしら。","ENG":"Will it be okay if it gets a little loud?","TWN":"場面稍微鬧大一點沒關係嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"물적 피해에 대한 배상과 은폐는 관리국의 관련 부서가 처리할 겁니다.","JPN":"物理的被害に対する賠償や隠ぺい工作は、管理局の関係部署が対処するでしょう。","ENG":"Compensation for damages and cover-up will be handled by the relevant departments of the Administration.","TWN":"關於物質損害賠償和掩蓋工作，將會由管理局的有關部門負責處理。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"부전대장님께서는 안심하시고 작전에 임해주십시오.","JPN":"副戦隊長は気兼ねなく作戦に臨んでください。","ENG":"So you can carry out the operation without any worries, Deputy Commander.","TWN":"副戰隊長，請放心執行作戰。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래? 그럼 안심이지~","JPN":"あ、そう？　じゃあ安心ね。","ENG":"Oh? That's good to hear.","TWN":"嗯？那麼我就放心了～"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자, 시작해 볼까?","JPN":"さて、始めようか？","ENG":"Then, shall we begin?","TWN":"好了，我們開始吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이제 그 침식체인가, 뭔가 하는 녀석들이 나타난다는 거지?","JPN":"これからその侵食体ってやつらが現れるってことだな。","ENG":"So those C.O. things are going to start appearing?","TWN":"所以？那個侵蝕體還是什麼的東西是不是就要出現了？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 그렇다고 너무 긴장할 필요는 없어.","JPN":"ふふ、でもそこまで緊張する必要はないよ。","ENG":"Fu fu, but there's no need to get anxious.","TWN":"呵呵，你不用這麼緊張。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"내 옆에만 붙어 있으면 아무 일도 없을 테니까.","JPN":"私の側にいれば大丈夫だから。","ENG":"Nothing will happen if you stay by my side.","TWN":"只要你待在我身邊，就不會有事的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};